1	export type Cell = [number, number];
2	
3	function isNeighbor([ax, ay]: Cell, [bx, by]: Cell): boolean {
4	  if (ax === bx && ay === by) return false;
5	  return Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;
6	}
7	
8	function countLiveNeighbors(cell: Cell, liveCells: Cell[]): number {
9	  return liveCells.filter((other) => isNeighbor(cell, other)).length;
10	}
11	
12	function survives(cell: Cell, liveCells: Cell[]): boolean {
13	  const n = countLiveNeighbors(cell, liveCells);
14	  return n === 2 || n === 3;
15	}
16	
17	export function nextGeneration(liveCells: Cell[]): Cell[] {
18	  return liveCells.filter((cell) => survives(cell, liveCells));
19	}
