1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a live cell alive when it has 2 live neighbors (survival)", () => {
15	    // Horizontal triple — middle cell (1,0) has 2 live neighbors, survives.
16	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
17	    expect(result).toContainEqual([1, 0]);
18	  });
19	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
20	    // 3x3 filled — center (1,1) has 8 live neighbors → dies
21	    const filled3x3: [number, number][] = [
22	      [0, 0], [1, 0], [2, 0],
23	      [0, 1], [1, 1], [2, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ];
26	    const result = nextGeneration(filled3x3);
27	    expect(result).not.toContainEqual([1, 1]);
28	  });
